class Edge(object):
    def __init__(self, u, v, id=0, w=0):
        self.u = u
        self.v = v
        self.id = id
        self.w = w


class UDGraph(object):
    def __init__(self, n, m):
        self.n = n
        self.m = m
        self.graph = [[] for i in range(n+1)]
        self.cc = [i for i in range(n+1)]
        self.cc_num = 0
        self.back_refs = {}
        self.degree = None

    def _dfs(self, u, vis):
        for e in self.graph[u]:
            if vis[e.v] < 0:
                vis[e.v], self.cc[e.v] = e.id, self.cc_num
                self._dfs(e.v, vis)
            else:
                if e.id != vis[u]:
                    self.back_refs[e.id] = e

    def add_edge(self, u, v, id):
        e1 = Edge(u, v, id, 0)
        self.graph[u].append(e1)
        e2 = Edge(v, u, id, 0)
        self.graph[v].append(e2)

    def get_cc(self):
        if self.cc_num <= 0:
            vis = [-1 for i in range(self.n+1)]
            for i in range(1, self.n+1):
                if vis[i] < 0:
                    self.cc_num += 1
                    vis[i], self.cc[i] = 0, self.cc_num
                    self._dfs(i, vis)

        return self.cc.copy(), self.cc_num

    def get_degree(self):
        if not self.degree:
            self.degree = [0] * (self.n+1)
            for u in range(1, self.n+1):
                s = set()
                for e in self.graph[u]:
                    if e.v != u:
                        s.add(e.v)
                self.degree[u] = len(s)
        return self.degree.copy()

    def has_point_loop(self):
        for i in range(1, self.n+1):
            for e in self.graph[i]:
                if i == e.v:
                    return True
        return False

    def has_edge_loop(self):
        self.get_cc()
        return len(self.back_refs) > 0

    def has_loop(self):
        return self.has_point_loop() or self.has_edge_loop()

    def has_repeating_edge(self):
        for u in range(1, self.n+1):
            s = set()
            for e in self.graph[u]:
                if e.v not in s:
                    s.add(e.v)
                else:
                    return True
        return False


