MOD = 10**9 + 7


def inv(x):
    return pow(x, MOD - 2, MOD)


class Number:
    def __init__(self, value, length):
        self.value = value % MOD
        self.length = length % (MOD - 1)

    def __add__(self, other):
        value = self.value * pow(10, other.length, MOD) + other.value
        length = self.length + other.length
        return Number(value, length)

    def __mul__(self, other):
        base = pow(10, self.length, MOD)
        if base == 1:
            value = self.value * other
        else:
            value = self.value * (pow(base, other, MOD) - 1) * inv(base - 1)
        return Number(value, self.length * other)

    @classmethod
    def _range(cls, a, r, rpow, length):
        base = pow(10, length, MOD)
        u = pow(base, rpow, MOD) - 1
        v = inv(base - 1)
        return cls((a * u + u * v - r) * v, length * rpow)

    @classmethod
    def range(cls, a, b):
        a, b, la, lb = int(a), int(b) + 1, len(a), len(b)
        if la == lb:
            return cls._range(a, b - a, b - a, la)
        term = cls._range(a, p[la] - a, q[la] - a, la)
        for i in range(la + 1, lb):
            term += cls._range(p[i - 1], p[i] - p[i - 1], q[i] - q[i - 1], i)
        term += cls._range(p[lb - 1], b - p[lb - 1], b - q[lb - 1], lb)
        return term


def parse_term(start, stop):
    if s[stop - 1] == ")":
        left = s.index("(", start)
        return parse_expression(left + 1, stop - 1) * int(s[start:left])

    try:
        sep = s.index("-", start, stop)
    except ValueError:
        return Number(int(s[start:stop]), stop - start)

    return Number.range(s[start:sep], s[sep + 1 : stop])


def parse_expression(start, stop):
    expression = Number(0, 0)
    i = start
    while i < stop:
        if s[i] == "+":
            expression += parse_term(start, i)
            start = i + 1
        i = right[i] if s[i] == "(" else i + 1
    expression += parse_term(start, i)
    return expression


s = input()
n = len(s)

p = [1]
for _ in range(n):
    p.append(p[-1] * 10 % MOD)
q = [1]
for _ in range(n):
    q.append(q[-1] * 10 % (MOD - 1))

right = [None] * n
stack = []
for i, x in enumerate(s):
    if x == "(":
        stack.append(i)
    elif x == ")":
        right[stack.pop()] = i

print(parse_expression(0, n).value)
